mapper.sql:
WHERE ian.ian_owr_id = #{owrId}

    AND ian.ian_send_stts_cd = #{sendSttsCd}


    AND (
        UPPER(ian.ian_no) LIKE '%' || UPPER(#{keyword}) || '%'
        OR UPPER(ian.ian_trc_no) LIKE '%' || UPPER(#{keyword}) || '%'
        OR UPPER(ian.ian_curr_loc) LIKE '%' || UPPER(#{keyword}) || '%'
    )
